def get_divisible_by_five(nums:list[int]):
    res = []
    for n in nums:
        if n % 5: res.append(n)
    return res

def list_merger(list1:list[int], list2:list[int]):
    list1_len = len(list1)
    merged_list = []
    if list1_len == 0 or len(list2) == 0: return merged_list
    for i in range(list1_len): merged_list.append(list1[i])
    for i in range(list1_len): merged_list.append(list2[i])
    return merged_list

def odd_even_sorter(nums:list[int]):
    even = []; odd = []
    if len(nums) == 0: return []
    for num in nums:
        if num % 2 == 0: even.append(num)
        else: odd.append(num)
    return f"Even: {even} \n Odd: {odd}"

