        for i in range(size + 1):
            if not include_zero:
                nums.append(i) 
            else:
                nums.append(i)
    return nums

def divide_all(nums:list[int]):
    divisor = nums[0]
    if len(nums) == 0: return divisor
    for num in nums:
        if num != divisor:
            divisor = divisor / num
    return divisor

