def bracket_pair_checker(formula:str):
    have_parens = '(' in formula or ')' in formula
    have_brackets = '[' in formula or ']' in formula
    if have_parens:
        if formula.count("(") != formula.count(")"): return "check your parenthesis"
    elif have_brackets:
        if formula.count("[") != formula.count("]"): return "check your brackets"
    return "all good"

